    <script>
        // Gauge configuration
        const config = {
            minRPM: 0,
            maxRPM: 12,
            redlineRPM: 10,
            startAngle: 135,
            endAngle: 405,
            centerX: 210,
            centerY: 210,
            radius: 160
        };

        // State
        let currentRPM = 1.5; // Start at idle
        let targetRPM = 1.5;
        let lastUpdate = Date.now();

