        }

        .needle-glow {
            filter: drop-shadow(0 0 8px rgba(255, 51, 102, 0.9)) drop-shadow(0 0 20px rgba(255, 51, 102, 0.5));
        }

        .center-hub {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            z-index: 10;
        }

        .center-hub svg {
            filter: drop-shadow(0 3px 6px rgba(0,0,0,0.5));
        }

        /* Tick mark styles */
        .tick-major {
            stroke: #ffffff;
            stroke-width: 3;
        }
        .tick-minor {
            stroke: #888888;
            stroke-width: 1.5;
        }
        .tick-label {
            font-family: 'Orbitron', monospace;
            font-size: 18px;
            fill: #e0e0e0;
            text-anchor: middle;
        }
        .redline-tick {
            stroke: #ff4d4d;
            stroke-width: 3;
        }
    </style>
</head>
<body>
    <div class="glow-ring"></div>
    <div class="gauge-container">
