{"content":"<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Motorcycle RPM Gauge</title>
    <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Inter:wght@400;500&display=swap" rel="stylesheet">
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            background: #0a0a0f;
            background: radial-gradient(ellipse at center, #1a1a2e 0%, #0a0a0f 70%);
            font-family: 'Inter', sans-serif;
            overflow: hidden;
        }

        .gauge-container {
            position: relative;
            width: 450px;
            height: 450px;
        }

        .gauge-bezel {
            position: absolute;
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background: linear-gradient(145deg, #3a3a4a, #1a1a2a);
            box-shadow: 
                0 0 60px rgba(255, 51, 102, 0.15),
                inset 0 2px 4px rgba(255, 255, 255, 0.1),
                0 20px 60px rgba(0, 0, 0, 0.8);
        }

        .gauge-face {
            position: absolute;
            top: 15px;
            left: 15px;
            right: 15px;
            bottom: 15px;
            border-radius: 50%;
            background: linear-gradient(180deg, #1a1a2e 0%, #0f0f1a 100%);
            overflow: hidden;
        }

        .gauge-svg {
            width: 100%;
            height: 100%;
            position: relative;
            z-index: 5;
        }

        .digital-readout {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            margin-top: 35px;
            background: rgba(10, 10, 15, 0.85);
            padding: 10px 24px;
            border-radius: 6px;
            border: 1px solid #333;
            box-shadow: 
                inset 0 2px 8px rgba(0,0,0,0.8),
                0 0 15px rgba(0, 255, 136, 0.1);
            z-index: 2;
        }

        .rpm-value {
            font-family: 'Orbitron', monospace;
            font-size: 28px;
            font-weight: 700;
            color: #00ff88;
            text-shadow: 0 0 20px rgba(0, 255, 136, 0.8);
            letter-spacing: 2px;
        }

        .rpm-label {
            font-family: 'Inter', sans-serif;
            font-size: 10px;
            color: #888;
            text-align: center;
            margin-top: 2px;
            letter-spacing: 3px;
        }

        .glow-ring {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 500px;
            height: 500px;
            border-radius: 50%;
            background: radial-gradient(circle, rgba(255, 51, 102, 0.1) 0%, transparent 70%);
            pointer-events: none;
            animation: pulse 2s ease-in-out infinite;
