        .tick-major {
            stroke: #ffffff;
            stroke-width: 3;
        }
        .tick-minor {
            stroke: #888888;
            stroke-width: 1.5;
        }
        .tick-label {
            font-family: 'Orbitron', monospace;
            font-size: 18px;
            fill: #e0e0e0;
            text-anchor: middle;
        }
        .redline-tick {
            stroke: #ff4d4d;
            stroke-width: 3;
        }
    </style>
</head>
